        return -1;
    }
    if (PyType_Ready(&PyUFunc_Type) < 0) {
        Py_CLEAR(PyUFunc_Type.tp_dict);
        return -1;
    }

    PyArrayDTypeMeta_Type.tp_base = &PyType_Type;
    if (PyType_Ready(&PyArrayDTypeMeta_Type) < 0) {
        return -1;
